CREATE VIEW `dim_kpi_user_info_view` (`user_id` COMMENT "主键", `real_user_id` COMMENT "真实用户id", `account` COMMENT "登录账号", `nick_name` COMMENT "用户姓名", `pwd` COMMENT "密码 MD5加密存储", `user_type` COMMENT "用户类型 1：超级管理员，2：普通用户", `role_id` COMMENT "角色", `phone` COMMENT "手机", `ding_id` COMMENT "钉钉id", `email` COMMENT "邮箱", `create_time` COMMENT "创建时间", `create_time_end` COMMENT "创建时间", `update_time` COMMENT "更新时间", `del_flag` COMMENT "删除标志 0：未删除 1：已删除", `last_login_time` COMMENT "最后登录时间", `employee_type` COMMENT "雇佣类型", `attribute` COMMENT "管理特性分类", `dead_line_3` COMMENT "最后时间线", `dead_line` COMMENT "4,8,8,10", `ding_user_id` COMMENT "dingdinguserid", `ding_talk_id` COMMENT "dingtalkid")
COMMENT "绩效系统-员工工号姓名" AS SELECT `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`userid` AS `user_id`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`realuserid` AS `real_user_id`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`account`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`nickname` AS `nick_name`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`pwd`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`usertype` AS `user_type`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`roleid` AS `role_id`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`phone`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`dingid` AS `ding_id`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`email`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`createtime` AS `create_time`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`createtimeend` AS `create_time_end`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`updatetime` AS `update_time`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`delflag` AS `del_flag`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`lastlogintime` AS `last_login_time`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`employeetype` AS `employee_type`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`attribute`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`deadline_3` AS `dead_line_3`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`deadline` AS `dead_line`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`dinguserid` AS `ding_user_id`, `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`.`dingtalkid` AS `ding_talk_id`
FROM `ods`.`ods_tidb_sharpengine_kpi_b_userinfo_tb`;
